// Fetch each Drive file and return base64 data + metadata
const params = $('When Called').first().json.body.action.params;
const accessToken = $('Get Google Token').first().json.access_token;
const fileIds = params.drive_file_ids || [];

const attachments = [];
for (const fileId of fileIds) {
  // Get file metadata
  const metaRes = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?fields=name,mimeType`, {
    headers: { Authorization: `Bearer ${accessToken}` }
  });
  const meta = await metaRes.json();

  // Download file content
  const fileRes = await fetch(`https://www.googleapis.com/drive/v3/files/${fileId}?alt=media`, {
    headers: { Authorization: `Bearer ${accessToken}` }
  });
  const buffer = Buffer.from(await fileRes.arrayBuffer());
  const base64 = buffer.toString('base64');

  attachments.push({ filename: meta.name, mimeType: meta.mimeType, base64 });
}

return [{ json: { attachments } }];

const params = $('When Called').first().json.body.action.params;
const actionType = $('When Called').first().json.body.action.type;
const accessToken = $('Get Google Token').first().json.access_token;
const attachments = $input.first().json?.attachments || [];

const boundary = `mc_boundary_${Date.now()}`;
const isHtml = params.is_html || false;
const contentType = isHtml ? 'text/html' : 'text/plain';

// Build headers
const headers = [];
if (actionType === 'GMAIL_REPLY' && params.thread_id) {
  // For replies, we need In-Reply-To header
  headers.push(`In-Reply-To: <${params.message_id}>`);
  headers.push(`References: <${params.message_id}>`);
}

let mime;
if (attachments.length === 0) {
  // Simple message
  const msgHeaders = [
    `To: ${params.to}`,
    params.cc ? `Cc: ${params.cc}` : null,
    `Subject: ${params.subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: ${contentType}; charset=utf-8`,
    ...headers,
  ].filter(Boolean).join('\r\n');
  mime = `${msgHeaders}\r\n\r\n${params.body}`;
} else {
  // Multipart message with attachments
  const msgHeaders = [
    `To: ${params.to}`,
    params.cc ? `Cc: ${params.cc}` : null,
    `Subject: ${params.subject}`,
    `MIME-Version: 1.0`,
    `Content-Type: multipart/mixed; boundary="${boundary}"`,
    ...headers,
  ].filter(Boolean).join('\r\n');

  const bodyPart = [
    `--${boundary}`,
    `Content-Type: ${contentType}; charset=utf-8`,
    `Content-Transfer-Encoding: quoted-printable`,
    ``,
    params.body,
  ].join('\r\n');

  const attachParts = attachments.map(a => [
    `--${boundary}`,
    `Content-Type: ${a.mimeType}; name="${a.filename}"`,
    `Content-Disposition: attachment; filename="${a.filename}"`,
    `Content-Transfer-Encoding: base64`,
    ``,
    a.base64,
  ].join('\r\n')).join('\r\n');

  mime = `${msgHeaders}\r\n\r\n${bodyPart}\r\n${attachParts}\r\n--${boundary}--`;
}

const raw = Buffer.from(mime).toString('base64url');
const threadId = params.thread_id || null;
return [{ json: { raw, threadId, accessToken } }];
